/* =========================
LOAD CARDS
========================= */
function loadHackathons(list){
  hackGrid.innerHTML="";
  list.forEach(hack=>{
    const card=document.createElement("div");
    card.className="hack_card";
    card.innerHTML=`
      <div class="hack_img">
        <img src="${hack.image}">
      </div>
      <div class="hack_content">
        <div class="hack_title">${hack.title}</div>
        <div class="hack_duration">${hack.duration}</div>
        <button class="hack_btn">View Details</button>
      </div>
    `;
    card.onclick=()=>showDetails(hack.id);
    hackGrid.appendChild(card);
  });
}

loadHackathons(hackathons);

/* =========================
SEARCH
========================= */
searchInput.addEventListener("input",()=>{
  const search=searchInput.value.toLowerCase();
  const filtered=hackathons.filter(h=>
    h.title.toLowerCase().includes(search)
  );
  loadHackathons(filtered);
});

/* =========================
SHOW DETAILS
========================= */
function showDetails(id){
  const data = hackathons.find(h=>h.id===id);
  if(!data) return;

  /* switch UI */
  listView.style.display="none";
  detailView.style.display="block";

  /* set data */
  document.getElementById("hack_title").innerText = data.title;
  document.getElementById("hack_desc").innerText = data.desc;

  /* timeline */
  const timeline = document.getElementById("timeline");
  timeline.innerHTML="";
  data.timeline.forEach(item=>{
    const li=document.createElement("li");
    li.innerText=item;
    timeline.appendChild(li);
  });

  /* rules */
  const rules = document.getElementById("rules");
  rules.innerHTML="";
  data.rules.forEach(item=>{
    const li=document.createElement("li");
    li.innerText=item;
    rules.appendChild(li);
  });

  /* prizes */
  const prizes = document.getElementById("prizes");
  prizes.innerHTML="";
  data.prizes.forEach(item=>{
    const li=document.createElement("li");
    li.innerText=item;
    prizes.appendChild(li);
  });

  /* =========================
  REGISTER LINK LOGIC
  ========================= */
  document.getElementById("register_btn").onclick = () => {
    window.open(data.link, "_blank"); 
  };
}

/* =========================
BACK BUTTON
========================= */
window.goBack = function(){
  detailView.style.display="none";
  listView.style.display="block";
};